import{_ as i,o as t,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"45. Medical Scientists Merit Reclassification Guidelines","description":"","frontmatter":{"title":"45. Medical Scientists Merit Reclassification Guidelines","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mspp/classification-salaries/45-medical-scientists-merit-reclassification-guidelines.md","filePath":"ebas/mspp/classification-salaries/45-medical-scientists-merit-reclassification-guidelines.md"}'),a={name:"ebas/mspp/classification-salaries/45-medical-scientists-merit-reclassification-guidelines.md"};function n(r,e,c,l,p,d){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_45-medical-scientists-merit-reclassification-guidelines" tabindex="-1">45. Medical Scientists Merit Reclassification Guidelines <a class="header-anchor" href="#_45-medical-scientists-merit-reclassification-guidelines" aria-label="Permalink to &quot;45. Medical Scientists Merit Reclassification Guidelines&quot;">​</a></h1><p><strong>45.1</strong> Guidelines for merit reclassification of Medical Scientists The following merit reclassification guidelines shall apply on the basis that:</p><p><strong>a.</strong> Merit reclassification provisions do not take into account supervisory roles, management functions, or responsibilities of Scientists which are covered under the specific weighing factors formula.</p><p><strong>b.</strong> Scientists employed in clinical diagnostic laboratories, with limited opportunities to pursue research and development work, are not excluded form career advancement on the basis of merit.</p><p><strong>c.</strong> A reclassification on merit is a personal classification, based on the personal skills, attributes and capacities of the individual irrespective of organisational structure.</p><p><strong>d.</strong> Scientists who are re-classified under this clause will be expected to continue to exercise the particular capabilities, skills and responsibilities which may have been the basis of their reclassification.</p><p><strong>e.</strong> The Employer may provide an Employee with duties commensurate with the identified abilities and competencies in the relevant merit review classification level descriptors.</p><p><strong>45.2</strong> Scientist Grade 2</p><p><strong>a.</strong> Is a Scientist appointed to this grade, and/or who is employed on work which requires special knowledge or depth of experience, and/or requires the application of a level of performance worthy of additional remuneration.</p><p><strong>b.</strong> Experienced Scientists who can perform, without direct supervision, a wide range of diagnostic tests or procedures, and or work which requires specialised knowledge.</p><p><strong>c.</strong> At this level, Scientists are required to have achieved a high level of performance and to have shown a commitment to further professional development.</p><p><strong>d.</strong> To satisfy these requirements, Scientists must comply with at least four of the following criteria:</p><p><strong>(i)</strong> demonstrated experience and competence in the performance and understanding of a wide range of diagnostic tests or procedures or of complex and specialised tests;</p><p><strong>(ii)</strong> demonstrated ability in giving professional advice within and outside the laboratory on appropriate scientific and clinical matters;</p><p><strong>(iii)</strong> participation in laboratory programmes for training of undergraduates and graduate scientific staff;</p><p><strong>(iv)</strong> demonstrated ability to initiate and develop new diagnostic or research procedures applicable in their laboratory environment;</p><p><strong>(v)</strong> demonstrated ability to critically assess and evaluate new equipment, instruments or products relevant to the diagnostic work of their laboratory;</p><p><strong>(vi)</strong> a recognised role in a development or research project approved by the employing institution. The significance of their role will be</p><p>demonstrated by their presentation of results at scientific meetings or by publications in scientific journals;</p><p><strong>(vii)</strong> being enrolled for a Membership of the Australian Association of Clinical Biochemists (MAACB), Diploma of Bacteriology, Master Science (M.Sc.), Master Applied Science (M. App. Sc.), Member of the Australian Institute of Physics (MAIP), Fellowship of the Human Genetics Society of Australia (FHGSA), Fellowship of the Medical Laboratory Scientist, Graduate Diploma in Health Administration, Doctor of Science,(D.Sc.), Doctor of Philosophy (Ph.D.), Fellowship of the Australian Institute of Medical Science (FAIMS), Member of Human Genetics Society of Australia MHGSA, Graduate Diploma Biostatistics, Graduate Diploma Epidemiology, Master of Applied Epidemiology, MPH, Master of Epidemiology or any other recognised equivalent Degree or Diploma relevant to medical sciences from a tertiary institution pursuant to clause of this Agreement where they have passed some subjects or where they, in the opinion of their academic supervisors, have made satisfactory progress for the success of the scientific thesis.</p><p><strong>45.3</strong> Scientist Grade 3</p><p><strong>a.</strong> Is a Scientist appointed to this grade and/or who has been qualified (as defined) for at least eight years and is engaged on specialised scientific work or work of a research or developmental nature.</p><p><strong>b.</strong> Widely experienced Scientists with sound knowledge and skills relating to an extensive range of diagnostic tests or procedures, and/or work of a specialised nature. At this level, Scientists may validate test results or be engaged in work of a research or developmental nature and are expected to have achieved a high level of professional development.</p><p><strong>c.</strong> To satisfy these requirements Scientists must:</p><p><strong>(i)</strong> would normally have a minimum of eight years professional experience;</p><p><strong>(ii)</strong> have satisfied at least four of the merit criteria for Scientist grade 2.</p><p><strong>(iii)</strong> Other factors to be taken into consideration are:</p><p><strong>(iv)</strong> demonstrated experience and expertise in the direct performance and interpretation of a wide range of diagnostic procedures and/or in the evaluation, operation and maintenance of complex equipment and instruments;</p><p><strong>(v)</strong> demonstrated commitment to professional development. Elements which will be taken into consideration include, inter alia: <strong>(A)</strong> regular participation in meetings of professional organisations; <strong>(B)</strong> membership of professional committees; <strong>(C)</strong> teaching activities.</p><p><strong>(vi)</strong> academic development achieved. The following qualifications will be considered:</p><p><strong>(A)</strong> Membership of the Australian Association of Clinical Biochemists (MAACB), Diploma of Bacteriology, Master of Science (M.Sc.), Master of Applied Science (M.App.Sc.), Membership of the Australian Institute of Physics (MAIP), Fellow of the Human Genetics Society of Australia (FHGSA), Graduate Diploma in Health Administration, Doctor of Science (D.Sc.), Doctor of Philosophy (Ph.D.), Fellow of the Australian Association of Clinical Biochemists (FAACB), Fellow of the Australian Institute of Medical Scientists (FAIMS), Fellow of the Australian Institute of Physics (FAIP), Fellow of the Institute of Medical Laboratory Scientists (FIMLS), Member of the Royal College of Pathologists, Graduate Diploma Epidemiology, Graduate Diploma Biostatistics, Member of the Human Genetics Society of Australia (MHGSA), Master of Applied Epidemiology, Master of Public Health (MPH), Master of Epidemiology or any other recognised equivalent Degree or Diploma relevant to medical sciences from a tertiary institution pursuant to <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a>, <a href="/eba/ebas/mspp/operation/6-savings-clause.html">clause 6.14</a> of this Agreement; <strong>(B)</strong> publications in which the applicant is a major contributor; <strong>(C)</strong> presentations at scientific meetings relevant to medical sciences; <strong>(D)</strong> academic appointments.</p><p><strong>(vii)</strong> demonstrated experience in: <strong>(A)</strong> maintaining laboratory statistics; <strong>(B)</strong> formulating and maintaining programmes for the development and cost containment of the laboratory’s work; <strong>(C)</strong> making budgetary submissions for their area.</p><p><strong>45.4</strong> Scientist Grade 4</p><p><strong>a.</strong> A Scientist appointed as such would normally have at least ten years&#39; experience, utilising advanced and specialised professional knowledge and experience.</p><p><strong>b.</strong> Very experienced Scientists with advanced and specialised professional knowledge relating to one or more disciplines of medical science. At this level, Scientists are expected to have made significant contributions to medical science and to be recognised as local experts in a relevant scientific and/or diagnostic speciality or activity.</p><p><strong>c.</strong> To satisfy these requirements, scientists must:</p><p><strong>(i)</strong> would normally have a minimum of ten years professional experience;</p><p><strong>(ii)</strong> have satisfied most of the criteria for a scientist grade 3;</p><p><strong>(iii)</strong> have a high standing in the scientific community as assessable on the basis of: qualifications; awards; past appointments; publications; membership of committees and of professional organisations;</p><p>consultancies; research grants in which the applicant is the principal or associate investigator; teaching appointments/commitments.</p><p><strong>(iv)</strong> Other factors to be taken into consideration are: <strong>(A)</strong> capacity in formulating, initiating and conducting programmes devoted to laboratory organisation, introduction of new procedures in service, development and research; and <strong>(B)</strong> assessing the value of such programmes in relating to the medical objectives and priorities of the employing Institution.</p><p><strong>45.5</strong> Scientist Grade 5 All such applications shall, where disputed, be considered by the Committee constituted with an independent chairperson.</p><p>Plain language terms: reclassification, merit review.</p>',43)])])}const h=i(a,[["render",n]]);export{m as __pageData,h as default};
